    37		r.mu.Lock()
    38		defer r.mu.Unlock()
    39		if r.members[nodeID] {
    40			return
    41		}
    42		r.members[nodeID] = true
    43		r.memberCount++
    44		for i := 0; i < r.replicas; i++ {
