    51	// Remove deregisters a physical node from the ring.
    52	func (r *Ring) Remove(nodeID string) {
    53		r.mu.Lock()
    54		defer r.mu.Unlock()
    55		if !r.members[nodeID] {
    56			return
    57		}
    58		delete(r.members, nodeID)
    59		r.memberCount--
