    62		newRing := make([]uint32, 0, len(r.ring)-r.replicas)
    63		for _, h := range r.ring {
    64			if r.nodeMap[h] != nodeID {
    65				newRing = append(newRing, h)
    66			} else {
    67				delete(r.nodeMap, h)
    68			}
    69		}
