    73	// Lookup returns the physical node responsible for the given key.
    74	// Returns "" if the ring is empty.
    75	func (r *Ring) Lookup(key string) string {
    76		r.mu.RLock()
    77		defer r.mu.RUnlock()
    78		if len(r.ring) == 0 {
    79			return ""
    80		}
    81		h := keyHash(key)
    82		idx := sort.Search(len(r.ring), func(i int) bool { return r.ring[i] >= h })
    83		if idx >= len(r.ring) {
    84			idx = 0 // wrap around
    85		}
    86		return r.nodeMap[r.ring[idx]]
    87	}
