    89	// LookupN returns the N distinct physical nodes closest (clockwise) to the key.
    90	// Useful for replication factor decisions.
    91	func (r *Ring) LookupN(key string, n int) []string {
    92		r.mu.RLock()
    93		defer r.mu.RUnlock()
    94		if len(r.ring) == 0 || n <= 0 {
    95			return nil
    96		}
    97		if n > r.memberCount {
    98			n = r.memberCount
    99		}
