   101		h := keyHash(key)
   102		idx := sort.Search(len(r.ring), func(i int) bool { return r.ring[i] >= h })
   103	
   104		seen := make(map[string]bool)
   105		result := make([]string, 0, n)
   106		for i := 0; i < len(r.ring) && len(result) < n; i++ {
   107			pos := (idx + i) % len(r.ring)
   108			node := r.nodeMap[r.ring[pos]]
   109			if !seen[node] {
   110				seen[node] = true
   111				result = append(result, node)
   112			}
   113		}
   114		return result
   115	}
