   166	// TransferKeys computes which keys need to be transferred when a node is added.
   167	// Returns a map of sourceNode → []keys that should move to the new node.
   168	func (r *Ring) TransferKeys(newNodeID string, keys []string) map[string][]string {
   169		// Get current assignment
   170		before := make(map[string]string, len(keys))
   171		for _, k := range keys {
   172			before[k] = r.Lookup(k)
   173		}
   174	
   175		// Simulate adding on a temporary copy to avoid mutating the ring
   176		tmp := r.clone()
   177		tmp.Add(newNodeID)
   178	
   179		// Compute transfers
   180		transfers := make(map[string][]string)
   181		for _, k := range keys {
   182			after := tmp.Lookup(k)
   183			if after == newNodeID && before[k] != newNodeID {
   184				transfers[before[k]] = append(transfers[before[k]], k)
   185			}
   186		}
   187		return transfers
   188	}
